cat > /tmp/tracker_test.go << 'EOF'
package main

import (
	"fmt"
	"sync"
	"sync/atomic"
)

// Tracker records evaluation metrics for the evaluation engine.
type Tracker struct {
	totalEvaluations atomic.Int64
	matchCount       atomic.Int64
	errorCount       atomic.Int64
}

// Metrics returns a snapshot of the current metrics.
type Metrics struct {
	TotalEvaluations int64
	MatchCount       int64
	ErrorCount       int64
}

// NewTracker creates a new Tracker instance.
func NewTracker() *Tracker {
	return &Tracker{}
}

// RecordEvaluation increments the total evaluation counter.
func (t *Tracker) RecordEvaluation() {
	t.totalEvaluations.Add(1)
}

// RecordMatch increments the match count when an evaluation results in a successful match.
func (t *Tracker) RecordMatch() {
	t.matchCount.Add(1)
}

// RecordError increments the error count when an evaluation fails.
func (t *Tracker) RecordError() {
	t.errorCount.Add(1)
}

// GetMetrics returns a snapshot of the current metric values.
func (t *Tracker) GetMetrics() Metrics {
	return Metrics{
		TotalEvaluations: t.totalEvaluations.Load(),
		MatchCount:       t.matchCount.Load(),
		ErrorCount:       t.errorCount.Load(),
	}
}

func main() {
	tracker := NewTracker()

	// Test concurrent recording
	var wg sync.WaitGroup
	for i := 0; i < 100; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			tracker.RecordEvaluation()
			if i%3 == 0 {
				tracker.RecordMatch()
			}
			if i%5 == 0 {
				tracker.RecordError()
			}
		}()
	}

	wg.Wait()

	metrics := tracker.GetMetrics()
	fmt.Printf("Total Evaluations: %d\n", metrics.TotalEvaluations)
	fmt.Printf("Match Count: %d\n", metrics.MatchCount)
	fmt.Printf("Error Count: %d\n", metrics.ErrorCount)
}
EOF
go run /tmp/tracker_test.go

